			// State at index 2:
			// s=0: index 2 is not a peak. Cost = 0.
			dpB[0][0][0] = 0

			// s=1: index 2 is a peak. Cost = costs[2].
			dpB[0][1][1] = costs[i2]

			for i := 1; i < n-3; i++ {
				current_idx := indicesB[i]

