					// s=0: current_idx is NOT a peak
					dpB[i][j][0] = min(dpB[i-1][j][0], dpB[i-1][j][1])

					// s=1: current_idx IS a peak
					if j >= 1 {
						prev_cost := dpB[i-1][j-1][0]
						if prev_cost != INF {
							dpB[i][j][1] = prev_cost + costs[current_idx]
						}
					}
				}
			}

			// Final result for Case B: min of state 0 or 1 at n-2 (index n-2)
			costB_inner := min(dpB[n-4][k-1][0], dpB[n-4][k-1][1])

			if costB_inner != INF {
				minTotalCost = min(minTotalCost, cost0 + costB_inner)
			}
		}
	}

	if minTotalCost == INF {
		return -1
	}
	return minTotalCost
}

func min(a, b int64) int64 {
	if a < b {
		return a
	}
	return b
}
